  id INT AUTO_INCREMENT,
  flags SET DEFAULT NULL,
  PRIMARY KEY (id)
);

INSERT INTO test (flags) VALUES ('a');
INSERT INTO test (flags) VALUES ('b');
INSERT INTO test (flags) VALUES ('c');

UPDATE test
SET flags = flags | 'd'
WHERE id = 1;

SELECT * FROM test;
```

In this example, we're updating the row with `id = 1` to include the value `'d'` in the `flags` column.

Note that the `|` operator is used to add new values to the existing set. If you want to remove a value from the set, you can use the `&` operator, like this:

```sql
