import redis

class IndexCache:
    def __init__(self, index_name, redis_client):
        self.index_name = index_name
        self.redis_client = redis_client
        self.cache_key = f"index:{index_name}:cache"

    def get(self, key):
        return self.redis_client.get(self.cache_key + ":" + key)

    def set(self, key, value):
        self.redis_client.set(self.cache_key + ":" + key, value)

    def delete(self, key):
        self.redis_client.delete(self.cache_key + ":" + key)

    def delete_all(self):
        self.redis_client.delete(self.cache_key)
